import{_ as a,o as e,c as r,a2 as d}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"水牛城新闻（Buffalo News）","description":"","frontmatter":{},"headers":[],"relativePath":"03_companies/水牛城新闻.md","filePath":"03_companies/水牛城新闻.md"}'),l={name:"03_companies/水牛城新闻.md"};function h(o,t,i,n,u,s){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="水牛城新闻-buffalo-news" tabindex="-1">水牛城新闻（Buffalo News） <a class="header-anchor" href="#水牛城新闻-buffalo-news" aria-label="Permalink to &quot;水牛城新闻（Buffalo News）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>内容</th></tr></thead><tbody><tr><td>英文名</td><td>Buffalo News (原名 Buffalo Evening News)</td></tr><tr><td>行业</td><td>报纸/媒体</td></tr><tr><td>总部</td><td>纽约州水牛城</td></tr><tr><td>伯克希尔持股</td><td>100%（通过蓝筹印花收购）</td></tr><tr><td>收购年份</td><td>1977年</td></tr></tbody></table><h2 id="核心业务" tabindex="-1">核心业务 <a class="header-anchor" href="#核心业务" aria-label="Permalink to &quot;核心业务&quot;">​</a></h2><p>水牛城市唯一的日报，周一至周六出版晚报，周日出版周日版。</p><h2 id="收购故事" tabindex="-1">收购故事 <a class="header-anchor" href="#收购故事" aria-label="Permalink to &quot;收购故事&quot;">​</a></h2><h3 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h3><ul><li>1977年蓝筹印花收购</li><li>收购后立即推出周日版，挑战原有周日报纸Courier-Express</li></ul><h3 id="早期困境" tabindex="-1">早期困境 <a class="header-anchor" href="#早期困境" aria-label="Permalink to &quot;早期困境&quot;">​</a></h3><ul><li><strong>1977-1982年</strong>：与Courier-Express激烈竞争，持续亏损</li><li>1981年税前亏损106万美元</li><li>1982年税前亏损122万美元</li></ul><h3 id="最终胜利" tabindex="-1">最终胜利 <a class="header-anchor" href="#最终胜利" aria-label="Permalink to &quot;最终胜利&quot;">​</a></h3><ul><li><strong>1983年</strong>：Courier-Express关门，成为唯一日报</li><li>当年实现盈利，利润率约10%</li></ul><h2 id="核心竞争优势" tabindex="-1">核心竞争优势 <a class="header-anchor" href="#核心竞争优势" aria-label="Permalink to &quot;核心竞争优势&quot;">​</a></h2><h3 id="_1-渗透率领先" tabindex="-1">1. 渗透率领先 <a class="header-anchor" href="#_1-渗透率领先" aria-label="Permalink to &quot;1. 渗透率领先&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>数值</th><th>排名</th></tr></thead><tbody><tr><td>平日渗透率</td><td>-</td><td>美国前100大报纸第一</td></tr><tr><td>周日渗透率</td><td>83%</td><td>从十年前63%提升</td></tr></tbody></table><h3 id="_2-内容质量" tabindex="-1">2. 内容质量 <a class="header-anchor" href="#_2-内容质量" aria-label="Permalink to &quot;2. 内容质量&quot;">​</a></h3><ul><li><strong>新闻洞占比</strong>：50.9%（行业平均仅35-40%）</li><li>坚持高质量新闻内容</li><li>主编Murray Light坚持新闻质量</li></ul><h3 id="_3-广告效率" tabindex="-1">3. 广告效率 <a class="header-anchor" href="#_3-广告效率" aria-label="Permalink to &quot;3. 广告效率&quot;">​</a></h3><ul><li>预印插页收入从360万涨到810万美元（1983年）</li><li>分类广告强劲</li></ul><h2 id="管理团队" tabindex="-1">管理团队 <a class="header-anchor" href="#管理团队" aria-label="Permalink to &quot;管理团队&quot;">​</a></h2><h3 id="关键人物" tabindex="-1">关键人物 <a class="header-anchor" href="#关键人物" aria-label="Permalink to &quot;关键人物&quot;">​</a></h3><table tabindex="0"><thead><tr><th>姓名</th><th>职位</th><th>贡献</th></tr></thead><tbody><tr><td><a href="./../04_人物库/Stan_Lipsey.html">Stan Lipsey</a></td><td>管理者</td><td>成本控制出色，管理优秀</td></tr><tr><td>Murray Light</td><td>主编</td><td>坚持新闻质量标准</td></tr></tbody></table><h3 id="管理特点" tabindex="-1">管理特点 <a class="header-anchor" href="#管理特点" aria-label="Permalink to &quot;管理特点&quot;">​</a></h3><ul><li>成本控制严格</li><li>不降低新闻质量</li><li>保持高渗透率</li></ul><h2 id="巴菲特评价摘录" tabindex="-1">巴菲特评价摘录 <a class="header-anchor" href="#巴菲特评价摘录" aria-label="Permalink to &quot;巴菲特评价摘录&quot;">​</a></h2><blockquote><p>&quot;水牛城新闻的平日渗透率在美国前100大报纸中排名第一，周日渗透率约前三。&quot; —— 1984年股东信</p></blockquote><blockquote><p>&quot;新闻洞占版面50.9%，远高于行业平均35-40%。我们坚持提供读者真正想要的内容。&quot; —— 1984年股东信</p></blockquote><blockquote><p>&quot;Stan Lipsey的管理让报纸在极艰难竞争中存活并最终获胜。&quot; —— 1983年股东信</p></blockquote><h2 id="财务表现-摘录" tabindex="-1">财务表现（摘录） <a class="header-anchor" href="#财务表现-摘录" aria-label="Permalink to &quot;财务表现（摘录）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>年份</th><th>税前利润</th><th>备注</th></tr></thead><tbody><tr><td>1981</td><td>-106万美元</td><td>与Courier竞争亏损</td></tr><tr><td>1982</td><td>-122万美元</td><td>继续亏损</td></tr><tr><td>1983</td><td>+约10%利润率</td><td>Courier关门，开始盈利</td></tr><tr><td>1987</td><td>3,941万美元</td><td>税前利润</td></tr></tbody></table><h2 id="周日版成长" tabindex="-1">周日版成长 <a class="header-anchor" href="#周日版成长" aria-label="Permalink to &quot;周日版成长&quot;">​</a></h2><table tabindex="0"><thead><tr><th>时期</th><th>发行量</th><th>备注</th></tr></thead><tbody><tr><td>推出前</td><td>27.2万</td><td>Courier原有市场</td></tr><tr><td>1983年</td><td>36.7万</td><td>增长35%</td></tr></tbody></table><h2 id="在股东信中的年份" tabindex="-1">在股东信中的年份 <a class="header-anchor" href="#在股东信中的年份" aria-label="Permalink to &quot;在股东信中的年份&quot;">​</a></h2><p>1977, 1978, 1979, 1980, 1981, 1982, 1983, 1984, 1985, 1986, 1987</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./喜诗糖果.html">喜诗糖果</a> - 同为蓝筹印花收购</li><li><a href="./华盛顿邮报.html">华盛顿邮报</a> - 同为媒体持仓</li><li><a href="./首都城市ABC.html">首都城市/ABC</a> - 广播媒体持仓</li></ul><hr><p><em>最后更新：2026-04-09</em></p>',38)])])}const q=a(l,[["render",h]]);export{c as __pageData,q as default};
